sql:
SELECT DISTINCT c.customer_id, c.email
FROM customers c
JOIN emails e ON c.customer_id = e.customer_id;

SELECT customers.customer_id, purchases.purchase_amount
FROM customers
JOIN purchases ON customers.customer_id = purchases.customer_id;

external_knowledge:
- 'silver members' refers to customers with a 'silver' loyalty program status;
- 'prime of their youth' translates to customers aged between 25 and 35;
- 'financial footprint' refers to the total amount spent and the number of transactions and redemptions;
- 'planted more than five seeds' means the customer made more than 5 purchases;
- 'harvested over two fruits' means the customer redeemed more than 2 rewards.

sql:
SELECT DISTINCT customer_id
FROM purchases
WHERE purchase_amount > 1000;

SELECT customer_id, COUNT(web_interaction_id) AS total_web_interactions
FROM web_interactions
GROUP BY customer_id;

SELECT customers.customer_id, purchases.product
FROM customers
LEFT JOIN purchases ON customers.customer_id = purchases.customer_id;
